export function getDemoLabels(lang: string): string[] {
  const lbl = {
    p10: pick(lang, "demo_lbl_10pm"),
    p1:  pick(lang, "demo_lbl_1am"),
    p4:  pick(lang, "demo_lbl_4am"),
    p7:  pick(lang, "demo_lbl_7am"),
    now: pick(lang, "demo_lbl_now"),
  };
  return [lbl.p10, "", "", lbl.p1, "", "", lbl.p4, "", "", lbl.p7, "", lbl.now];
}

