export type RoomLocale = { idealDir: string; importance: string; dos: string[]; donts: string[]; remedies: string[] };
export function getRoomLoc(lang: string, roomKey: string): RoomLocale {
  return {
    idealDir:   pick(lang, "room_" + roomKey + "_idealDir"),
    importance: pick(lang, "room_" + roomKey + "_importance"),
    dos:        pickRange(lang, "room_" + roomKey + "_dos", roomDosCount(roomKey)),
    donts:      pickRange(lang, "room_" + roomKey + "_donts", roomDontsCount(roomKey)),
    remedies:   pickRange(lang, "room_" + roomKey + "_remedies", roomRemediesCount(roomKey)),
  };
}

function roomDosCount(roomKey: string): number {
  switch (roomKey) {
    case "main-door": return 6;
    case "living": return 5;
    case "kitchen": return 5;
    case "master-bedroom": return 5;
    case "children": return 5;
    case "pooja": return 5;
    case "bathroom": return 5;
    case "study": return 5;
    default: return 0;
  }
}
function roomDontsCount(roomKey: string): number {
  switch (roomKey) {
    case "main-door": return 5;
    case "living": return 4;
    case "kitchen": return 4;
    case "master-bedroom": return 4;
    case "children": return 3;
    case "pooja": return 4;
    case "bathroom": return 4;
    case "study": return 4;
    default: return 0;
  }
}
function roomRemediesCount(roomKey: string): number {
  switch (roomKey) {
    case "main-door": return 3;
    case "living": return 3;
    case "kitchen": return 3;
    case "master-bedroom": return 3;
    case "children": return 3;
    case "pooja": return 3;
    case "bathroom": return 3;
    case "study": return 3;
    default: return 0;
  }
}
